      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const px1 = x1 * GRID;
      const py1 = y1 * GRID;
      const px2 = x2 * GRID;
      const py2 = y2 * GRID;

      const isHorizontal = y1 === y2;
      const offset = 4;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={px1} y1={py1} x2={px2} y2={py2}
            stroke="#0f0"
            strokeWidth="2"
            style={{ cursor: 'pointer' }}
            onClick={(e) => {
              if (e.ctrlKey || e.metaKey) {
                handleBridgeRemove(e, key);
              }
            }}
            onContextMenu={(e) => handleBridgeRemove(e, key)}
          />
        );
      } else if (count === 2) {
        const dx = isHorizontal ? 0 : offset;
        const dy = isHorizontal ? offset : 0;
        lines.push(
          <line
            key={key + '_a'}
            x1={px1 - dx} y1={py1 - dy} x2={px2 - dx} y2={py2 - dy}
            stroke="#0f0"
            strokeWidth="2"
            style={{ cursor: 'pointer' }}
            onClick={(e) => {
              if (e.ctrlKey || e.metaKey) {
                handleBridgeRemove(e, key);
              }
            }}
            onContextMenu={(e) => handleBridgeRemove(e, key)}
          />
        );
        lines.push(
          <line
            key={key + '_b'}
            x1={px1 + dx} y1={py1 + dy} x2={px2 + dx} y2={py2 + dy}
            stroke="#0f0"
            strokeWidth="2"
            style={{ cursor: 'pointer' }}
            onClick={(e) => {
              if (e.ctrlKey || e.metaKey) {
                handleBridgeRemove(e, key);
              }
            }}
            onContextMenu={(e) => handleBridgeRemove(e, key)}
          />
        );
      }
    }
    return lines;
  };

  // Render islands
  const renderIslands = () => {
    return islands.map(island => {
      const px = island.x * GRID;
      const py = island.y * GRID;
      const isSelected = selectedIsland === island.id;

      return (
        <g key={island.id} onClick={() => handleIslandClick(island)} style={{ cursor: 'pointer' }}>
          <circle
            cx={px}
            cy={py}
            r={16}
            fill="black"
            stroke={isSelected ? '#ff0' : '#0f0'}
            strokeWidth={isSelected ? 3 : 2}
          />
          <text
            x={px}
            y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="monospace"
          >
            {island.value}
          </text>
        </g>
      );
    });
  };

  // Render keyboard cursor (rect, not circle)
  const renderCursor = () => {
    const cursorIsland = islands.find(i => i.id === cursorIslandId);
    if (!cursorIsland) return null;
    const px = cursorIsland.x * GRID;
    const py = cursorIsland.y * GRID;
    return (
      <rect
        x={px - 20}
        y={py - 20}
        width={40}
        height={40}
        fill="none"
        stroke={kbSelected ? '#ff0' : '#0ff'}
        strokeWidth={2}
        strokeDasharray="4 2"
        pointerEvents="none"
      />
    );
  };

  return (
    <div style={{ background: 'black', minHeight: '100vh', padding: 0, margin: 0 }}>
      <div style={{ padding: '10px', display: 'flex', alignItems: 'center', gap: '10px' }}>
        <select
          value={puzzleIndex}
          onChange={(e) => resetPuzzle(Number(e.target.value))}
          style={{
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            padding: '4px'
          }}
        >
          {puzzles.map((p, idx) => (
            <option key={p.id} value={idx}>{p.name}</option>
          ))}
        </select>
        <button
          onClick={() => {
            setBridges(new Map());
            setSelectedIsland(null);
            setError(null);
            setVictory(false);
            setCursorIslandId(0);
            setKbSelected(false);
          }}
          style={{
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            padding: '4px 8px',
            cursor: 'pointer'
          }}
        >
          Reset
        </button>
        {error && <span className="error-message" style={{ color: '#f00', fontFamily: 'monospace' }}>{error}</span>}
        {victory && <span className="victory-banner" style={{ color: '#0f0', fontFamily: 'monospace', fontSize: '20px', fontWeight: 'bold' }}>SOLVED!</span>}
      </div>
      <svg
        width={WIDTH}
        height={HEIGHT}
        style={{ display: 'block' }}
      >
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
